from pathlib import Path
import openpyxl
from datetime import datetime

def normalize_cell(val):
    if val is None:
        return ""
    if isinstance(val, datetime):
        return val.strftime("%Y-%m-%d %H:%M")
    return str(val).strip()

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob("*.xlsx"))
    if not xlsx_files:
        return {"pass": False, "score": 0.0, "feedback": "No .xlsx file found in workspace"}
    # Prefer the appeals_log file
    target_file = None
    for f in xlsx_files:
        if "appeal" in f.name.lower() or "log" in f.name.lower():
            target_file = f
            break
    if target_file is None:
        target_file = xlsx_files[0]
    try:
        wb = openpyxl.load_workbook(target_file, data_only=True)
        ws = wb.active
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open {target_file.name}: {e}"}

    def get_cell(row, col):
        return normalize_cell(ws.cell(row=row, column=col).value)

    # Row 7: I=9, J=10, K=11, N=14, O=15, P=16, Q=17
    i7 = get_cell(7, 9)
    j7 = get_cell(7, 10)
    k7 = get_cell(7, 11)
    n7 = get_cell(7, 14)
    o7 = get_cell(7, 15)
    p7 = get_cell(7, 16)
    q7 = get_cell(7, 17)

    failures = []
    # I7: receipt datetime — accept either 2026-11-03 14:15 or 2026-11-04 14:15
    if not ("14:15" in i7 and ("2026-11-03" in i7 or "2026-11-04" in i7)):
        failures.append(f"I7 expected '2026-11-03 14:15' or '2026-11-04 14:15', got '{i7}'")
    # J7: date only
    if not ("2026-11-03" in j7 or "2026-11-04" in j7):
        failures.append(f"J7 expected '2026-11-03' or '2026-11-04', got '{j7}'")
    # K7: N
    if k7.upper() not in ("N", "NO", "FALSE", "0"):
        failures.append(f"K7 expected 'N', got '{k7}'")
    # N7: decision deadline
    if not ("2026-11-05" in n7 and "10:00" in n7):
        failures.append(f"N7 expected '2026-11-05 10:00', got '{n7}'")
    # O7: contains Ontario and Parity
    if not ("ontario" in o7.lower() and "parity" in o7.lower()):
        failures.append(f"O7 expected to contain 'Ontario' and 'Parity', got '{o7}'")
    # P7: Y
    if p7.upper() not in ("Y", "YES", "TRUE", "1"):
        failures.append(f"P7 expected 'Y', got '{p7}'")
    # Q7: N
    if q7.upper() not in ("N", "NO", "FALSE", "0"):
        failures.append(f"Q7 expected 'N', got '{q7}'")

    if failures:
        return {"pass": False, "score": 0.0, "feedback": "Row 7 cell failures: " + "; ".join(failures)}
