from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check slack_data.json"}
    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}
    with open(slack_path, "r") as f:
        data = json.load(f)
    messages_by_channel = data.get("messages", {})

    # Find the escalation message in D001 referencing CASE-2026-00441
    target_text = None
    for msg in messages_by_channel.get("D001", []):
        if isinstance(msg, dict):
            text = msg.get("text", "")
            if "CASE-2026-00441" in text and "ESCALATION" in text.upper():
                target_text = text
                break
    # Fallback: any D001 message with the case ID
    if target_text is None:
        for msg in messages_by_channel.get("D001", []):
            if isinstance(msg, dict):
                text = msg.get("text", "")
                if "CASE-2026-00441" in text:
                    target_text = text
                    break

    if target_text is None:
        return {"pass": False, "score": 0.0, "feedback": "No DM in D001 (Darnell Whitfield) found referencing CASE-2026-00441"}

    lower = target_text.lower()
    upper = target_text.upper()

    # Check for Format B-2 structured fields
    checks = [
        ("ESCALATION" in upper, "missing 'ESCALATION' header (Format B-2)"),
        ("CASE-2026-00441" in target_text, "missing Case # CASE-2026-00441"),
        (
            bool(re.search(r'type[:\s]', lower)) and "concurrent" in lower,
            "missing 'Type:' field with 'Concurrent'",
        ),
        (
            bool(re.search(r'deadline[:\s]', lower)) and ("2026-11-05" in target_text or "november 5" in lower or "nov 5" in lower),
            "missing 'Deadline:' field with 2026-11-05 / November 5",
        ),
        (
            bool(re.search(r'trigger[:\s]', lower)),
            "missing 'Trigger:' field (must cite specific §9.2 trigger)",
        ),
        (
            bool(re.search(r'summary[:\s]', lower)),
            "missing 'Summary:' field",
        ),
        (
            bool(re.search(r'recommend', lower)),
            "missing 'My Recommendation:' / recommendation field",
        ),
        (
            bool(re.search(r'requested action[:\s]', lower)) or bool(re.search(r'action[:\s]', lower)),
            "missing 'Requested Action:' field",
        ),
    ]
    failures = [msg for passed, msg in checks if not passed]
    if failures:
        return {"pass": False, "score": 0.0, "feedback": f"D001 DM for CASE-2026-00441 found but missing B-2 template fields: {'; '.join(failures)}"}
    return {"pass": True, "score": 1.0, "feedback": "D001 DM found with Format B-2 escalation for CASE-2026-00441 (all required fields present per SOP §9.3 / Appendix B)"}
